select id, username, password, nickname, avatar, phone, email, gender, role_id, status, create_time, update_time from sys_user
and ( username like concat('%', #{keyword}, '%') or nickname like concat('%', #{keyword}, '%') or phone like concat('%', #{keyword}, '%') or email like concat('%', #{keyword}, '%') )
and status = #{status}
and role_id = #{roleId}
order by create_time desc
